374	type regenerateEnrollmentTokenResponse struct {
375		Token     string    `json:"token"`
376		ExpiresAt time.Time `json:"expires_at"`
377	}
378	
379	type rotateCertResponse struct {
380		NewKey         bool   `json:"new_key"`
381		CertificatePEM string `json:"certificate_pem,omitempty"`
382		CACertPEM      string `json:"ca_certificate_pem,omitempty"`
383	}
384	
385	// handleRotateCert implements POST /api/v1/hosts/{id}/rotate-cert?new_key=...
386	// (ADR 0004 §7.1 force-rotate).
387	//
388	//   - new_key=false (default): the server re-signs the existing public key
389	//     immediately and returns the new cert. The agent picks it up on the
390	//     next poll via SaveCertificateAndUpdateHostCert's overlap window.
391	//   - new_key=true: a pending_rekey flag is set on the host row. The next
392	//     poll response carries rekey_required + a single-use enrollment token
393	//     the agent uses to re-enroll its freshly generated keypair.
394	func (s *Server) handleRotateCert(w http.ResponseWriter, r *http.Request) {
395		id := chi.URLParam(r, "id")
396		newKey := strings.EqualFold(r.URL.Query().Get("new_key"), "true")
397	
398		host, err := s.store.GetHost(r.Context(), id)
399		if errors.Is(err, store.ErrNotFound) {
400			writeError(w, http.StatusNotFound, "host not found")
401			return
402		}
403		if err != nil {
404			s.logger.Error("get host for rotate-cert", "error", err)
405			writeError(w, http.StatusInternalServerError, "failed to get host")
406			return
407		}
408		ok, err := s.canAccessHost(r.Context(), host)
409		if err != nil {
410			s.logger.Error("authz check for rotate-cert", "error", err)
411			writeError(w, http.StatusInternalServerError, "authz check failed")
412			return
413		}
414		if !ok {
415			writeError(w, http.StatusForbidden, "forbidden")
416			return
417		}
418	
419		if newKey {
420			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
421				if errors.Is(err, store.ErrRekeyAlreadyPending) {
422					writeError(w, http.StatusConflict, "rekey already pending")
423					return
424				}
425				s.logger.Error("set pending rekey", "error", err)
426				writeError(w, http.StatusInternalServerError, "failed to schedule rekey")
427				return
428			}
429			s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=true")
430			writeJSON(w, http.StatusAccepted, rotateCertResponse{NewKey: true})
431			return
432		}
433	
434		certInfo, err := s.store.GetCertificateInfo(r.Context(), host.ID)
435		if err != nil {
436			s.logger.Error("get cert info for rotate-cert", "error", err)
437			writeError(w, http.StatusInternalServerError, "no current cert to re-sign")
438			return
439		}
440		signed, err := s.signHostCert(r.Context(), host, certInfo)
441		if err != nil {
442			s.logger.Error("sign cert for rotate-cert", "error", err)
443			writeError(w, http.StatusInternalServerError, "failed to sign new cert")
444			return
445		}
446		if err := s.store.SaveCertificateAndUpdateHostCert(r.Context(), host.ID, signed.certPEM, signed.fp, signed.notBefore, signed.notAfter); err != nil {
447			s.logger.Error("save rotated cert", "error", err)
448			writeError(w, http.StatusInternalServerError, "failed to persist new cert")
449			return
450		}
451		s.metrics.recordSignature(host.CAID)
452		s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=false")
453	
454		writeJSON(w, http.StatusOK, rotateCertResponse{
455			NewKey:         false,
456			CertificatePEM: string(signed.certPEM),
457			CACertPEM:      string(signed.caCertPEM),
458		})
459	}
460	
461	// handleReenroll is the explicit re-enrollment endpoint (ADR 0004 §7.1).
462	// It delegates to mintEnrollmentTokenForHost — identical mechanics to
463	// handleRegenerateEnrollmentToken — but exists as a separate route so
464	// operator UIs can present "re-enroll" as a discrete action (e.g. when a
465	// host has lost its key material), distinct from the "regenerate token"
466	// fix-up that handleRegenerateEnrollmentToken serves.
467	func (s *Server) handleReenroll(w http.ResponseWriter, r *http.Request) {
468		s.mintEnrollmentTokenForHost(w, r, "reenroll")
469	}
470	
471	// handleRegenerateEnrollmentToken mints a fresh single-use enrollment token
472	// bound to an existing host row (ADR 0004 §7.1 — "regenerates the token
473	// without churning the row"). Previous active tokens for the same host are
474	// invalidated atomically. The host row, its IP allocation, group membership,
475	// and audit history are preserved.
476	func (s *Server) handleRegenerateEnrollmentToken(w http.ResponseWriter, r *http.Request) {
477		s.mintEnrollmentTokenForHost(w, r, "regenerate-token")
478	}
479	
480	// mintEnrollmentTokenForHost is the shared implementation of the
481	// regenerate-token and reenroll endpoints. The reason argument flows into
482	// the audit details column so the timeline distinguishes the two.
483	func (s *Server) mintEnrollmentTokenForHost(w http.ResponseWriter, r *http.Request, reason string) {
484		id := chi.URLParam(r, "id")
485		host, err := s.store.GetHost(r.Context(), id)
486		if errors.Is(err, store.ErrNotFound) {
487			writeError(w, http.StatusNotFound, "host not found")
488			return
489		}
490		if err != nil {
491			s.logger.Error("get host", "error", err)
492			writeError(w, http.StatusInternalServerError, "failed to get host")
493			return
494		}
495		ok, err := s.canAccessHost(r.Context(), host)
496		if err != nil {
497			s.logger.Error("authz check", "error", err)
498			writeError(w, http.StatusInternalServerError, "authz check failed")
499			return
500		}
501		if !ok {
502			writeError(w, http.StatusForbidden, "forbidden")
503			return
504		}
505	
506		tokenStr := uuid.New().String()
507		expiresAt := time.Now().Add(s.tokenTTLFor(r.Context(), host.NetworkID))
508		if err := s.store.CreateTokenForHost(r.Context(), host.ID, tokenStr, expiresAt); err != nil {
509			s.logger.Error("create enrollment token", "error", err)
510			writeError(w, http.StatusInternalServerError, "failed to mint token")
511			return
512		}
513		details := host.Name
514		if reason != "" {
515			details = reason + ": " + host.Name
516		}
517		s.recordAuditAction(r.Context(), auditHostReenrollRequested, host.ID, details)
518	
519		writeJSON(w, http.StatusCreated, regenerateEnrollmentTokenResponse{
520			Token:     tokenStr,
521			ExpiresAt: expiresAt,
522		})
523	}
524	
525	func (s *Server) handleUpdateHost(w http.ResponseWriter, r *http.Request) {
526		id := chi.URLParam(r, "id")
527	
528		// Load host by ID
529		host, err := s.store.GetHost(r.Context(), id)
530		if errors.Is(err, store.ErrNotFound) {
531			writeError(w, http.StatusNotFound, "host not found")
532			return
533		}
534		if err != nil {
535			s.logger.Error("get host", "error", err)
536			writeError(w, http.StatusInternalServerError, "failed to get host")
537			return
538		}
539		ok, err := s.canAccessHost(r.Context(), host)
540		if err != nil {
541			s.logger.Error("authz check", "error", err)
542			writeError(w, http.StatusInternalServerError, "authz check failed")
543			return
544		}
545		if !ok {
546			writeError(w, http.StatusForbidden, "forbidden")
547			return
548		}
549	
550		// Decode request body (lenient for PATCH, forward-compatible)
551		var req updateHostRequest
552		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
553			writeError(w, http.StatusBadRequest, "invalid request body")
554			return
555		}
556	
557		// Snapshot before state for diff and triggers
558		before := *host
559		if before.Advanced != nil {
560			beforeAdv := *before.Advanced
561			before.Advanced = &beforeAdv
562		}
563	
564		// Validate and merge fields
565		if req.Name != nil {
566			name := strings.TrimSpace(*req.Name)
567			if name == "" {
568				writeError(w, http.StatusBadRequest, "name must not be empty")
569				return
570			}
571			host.Name = name
572		}
573	
574		if req.NebulaIPs != nil {
575			if err := validateHostIPs(r.Context(), s.store, host.NetworkID, *req.NebulaIPs, host.ID); err != nil {
576				if IsHostIPValidationError(err) {
577					writeError(w, http.StatusBadRequest, err.Error())
578					return
579				}
580				s.logger.Error("validate host ips", "error", err)
581				writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
582				return
583			}
584			host.NebulaIPs = *req.NebulaIPs
585		}
586	
587		if req.Groups != nil {
588			for _, g := range *req.Groups {
589				if strings.TrimSpace(g) == "" {
590					writeError(w, http.StatusBadRequest, "group names must not be empty")
591					return
592				}
593			}
594			host.Groups = *req.Groups
595		}
596	
597		if req.Role != nil {
598			role := models.HostRole(*req.Role)
599			if !models.ValidRole(role) {
600				writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", *req.Role))
601				return
602			}
603			host.Role = role
604			host.IsLighthouse = role == models.HostRoleLighthouse
605			host.IsRelay = role == models.HostRoleRelay
606		}
607	
608		if req.PublicIP != nil {
609			publicIP := strings.TrimSpace(*req.PublicIP)
610			if publicIP != "" {
611				if _, err := models.ValidateIPAddr("public_ip", publicIP); err != nil {
612					writeError(w, http.StatusBadRequest, err.Error())
613					return
614				}
615			}
616			host.PublicIP = publicIP
617		}
618	
619		if req.ListenPort != nil {
620			if *req.ListenPort < 0 || *req.ListenPort > 65535 {
621				writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
622				return
623			}
624			host.ListenPort = *req.ListenPort
625		}
626	
627		if req.Advanced != nil {
628			if err := validateHostAdvanced(req.Advanced); err != nil {
629				writeError(w, http.StatusBadRequest, err.Error())
630				return
631			}
632			host.Advanced = req.Advanced
633		}
634	
635		// Validate role reachability
636		if err := models.ValidateRoleReachability(host.Role, host.PublicIP, host.ListenPort); err != nil {
637			writeError(w, http.StatusBadRequest, err.Error())
638			return
639		}
640	
641		// Compute diff
642		diffJSON, hasChanges, err := models.HostDiff(&before, host)
643		if err != nil {
644			s.logger.Error("compute diff", "error", err)
645			writeError(w, http.StatusInternalServerError, "failed to compute diff")
646			return
647		}
648	
649		// If no changes, return 200 without updating
650		if !hasChanges {
651			writeJSON(w, http.StatusOK, host)
652			return
653		}
654	
655		// Update timestamp and persist
656		host.UpdatedAt = time.Now()
657		if err := s.store.UpdateHost(r.Context(), host); err != nil {
658			s.logger.Error("update host", "error", err)
659			writeError(w, http.StatusInternalServerError, "failed to update host")
660			return
661		}
662	
663		// Task 1.4: Re-publish triggers
664		// Force re-publish config for this host
665		if err := s.store.UpdateHostConfigVersion(r.Context(), host.ID, 0); err != nil {
666			s.logger.Error("reset host config version", "host", host.ID, "error", err)
667		}
668	
669		// If role changed, bump network config version for peer updates
670		if before.Role != host.Role {
671			if err := s.store.BumpNetworkConfigVersion(r.Context(), host.NetworkID); err != nil {
672				s.logger.Error("bump network config version", "network", host.NetworkID, "error", err)
673			}
674		}
675	
676		// If name or any IP changed, set pending rekey for cert re-enrollment
677		ipsEqual := len(before.NebulaIPs) == len(host.NebulaIPs)
678		if ipsEqual {
679			for i := range before.NebulaIPs {
680				if before.NebulaIPs[i] != host.NebulaIPs[i] {
681					ipsEqual = false
682					break
683				}
684			}
685		}
686		if before.Name != host.Name || !ipsEqual {
687			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
688				if !errors.Is(err, store.ErrRekeyAlreadyPending) {
689					s.logger.Error("set pending rekey", "host", host.ID, "error", err)
690				}
691				// Idempotent: ErrRekeyAlreadyPending is success (rekey already scheduled)
692			}
693			// Reload host to get PendingRekey flag in response
694			freshHost, err := s.store.GetHost(r.Context(), host.ID)
695			if err == nil {
696				host = freshHost
697			}
698		}
699	
700		// Record audit entry with diff
701		s.recordAuditAction(r.Context(), auditHostUpdate, host.ID, string(diffJSON))
702	
703		writeJSON(w, http.StatusOK, host)
704	}
705

