	if err != nil {
		s.logger.Error("list operators", "error", err)
		writeError(w, http.StatusInternalServerError, "failed to list operators")
		return
	}
	if ops == nil {
		ops = []*models.Operator{}
	}
	writeJSON(w, http.StatusOK, ops)
