75	func (s *Server) handleCreateCA(w http.ResponseWriter, r *http.Request) {
76		actor := ActorOf(r.Context())
77		if s.master == nil {
78			writeError(w, http.StatusServiceUnavailable, "CA creation requires NEBULA_MGMT_MASTER_KEY to be configured")
79			return
80		}
81	
82		var req createCARequest
83		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
84			writeError(w, http.StatusBadRequest, "invalid request body")
85			return
86		}
87		if req.Name == "" {
88			writeError(w, http.StatusBadRequest, "name is required")
89			return
90		}
91		duration := 365 * 24 * time.Hour
92		if req.Duration != "" {
93			d, err := time.ParseDuration(req.Duration)
94			if err != nil || d <= 0 {
95				writeError(w, http.StatusBadRequest, "invalid duration")
96				return
97			}
98			duration = d
99		}
100	
101		mgr, err := pki.NewCA(req.Name, duration)
102		if err != nil {
103			s.logger.Error("generate CA", "error", err)
104			writeError(w, http.StatusInternalServerError, "failed to generate CA")
105			return
106		}
107		rawKey := mgr.RawKey()
108		defer keystore.Zeroize(rawKey)
109	
110		dek, wrappedDEK, err := s.master.GenerateDEK()
111		if err != nil {
112			writeError(w, http.StatusInternalServerError, "failed to generate DEK")
113			return
114		}
115		defer keystore.Zeroize(dek)
116		wrappedKey, err := keystore.SealWithDEK(dek, rawKey)
117		if err != nil {
118			writeError(w, http.StatusInternalServerError, "failed to encrypt CA key")
119			return
120		}
121		certPEM, err := mgr.CACertPEM()
122		if err != nil {
123			writeError(w, http.StatusInternalServerError, "marshal CA cert")
124			return
125		}
126		fp, err := mgr.CACertFingerprint()
127		if err != nil {
128			writeError(w, http.StatusInternalServerError, "fingerprint CA cert")
129			return
130		}
131		now := time.Now()
132		c := &models.CA{
133			ID:                   uuid.New().String(),
134			Name:                 req.Name,
135			OwnerOperatorID:      actor.ID,
136			CertPEM:              string(certPEM),
137			Fingerprint:          fp,
138			NotBefore:            mgr.CACert().NotBefore(),
139			NotAfter:             mgr.CACert().NotAfter(),
140			Status:               models.CAStatusActive,
141			EncryptedKeyDEK:      wrappedDEK.Ciphertext,
142			NonceDEK:             wrappedDEK.Nonce,
143			EncryptedKeyMaterial: wrappedKey.Ciphertext,
144			NonceKey:             wrappedKey.Nonce,
145			CreatedAt:            now,
146			UpdatedAt:            now,
147		}
148		if err := s.store.CreateCA(r.Context(), c); err != nil {
149			s.logger.Error("insert CA", "error", err)
150			writeError(w, http.StatusInternalServerError, "failed to store CA")
151			return
152		}
153		s.recordAuditAction(r.Context(), auditCACreated, c.ID, c.Name)
154		writeJSON(w, http.StatusCreated, s.toCAResponse(c))
155	}
