379	type rotateCertResponse struct {
380		NewKey         bool   `json:"new_key"`
381		CertificatePEM string `json:"certificate_pem,omitempty"`
382		CACertPEM      string `json:"ca_certificate_pem,omitempty"`
383	}
384	
385	// handleRotateCert implements POST /api/v1/hosts/{id}/rotate-cert?new_key=...
386	// (ADR 0004 §7.1 force-rotate).
387	//
388	//   - new_key=false (default): the server re-signs the existing public key
389	//     immediately and returns the new cert. The agent picks it up on the
390	//     next poll via SaveCertificateAndUpdateHostCert's overlap window.
391	//   - new_key=true: a pending_rekey flag is set on the host row. The next
392	//     poll response carries rekey_required + a single-use enrollment token
393	//     the agent uses to re-enroll its freshly generated keypair.
394	func (s *Server) handleRotateCert(w http.ResponseWriter, r *http.Request) {
395		id := chi.URLParam(r, "id")
396		newKey := strings.EqualFold(r.URL.Query().Get("new_key"), "true")
397	
398		host, err := s.store.GetHost(r.Context(), id)
399		if errors.Is(err, store.ErrNotFound) {
400			writeError(w, http.StatusNotFound, "host not found")
401			return
402		}
403		if err != nil {
404			s.logger.Error("get host for rotate-cert", "error", err)
405			writeError(w, http.StatusInternalServerError, "failed to get host")
406			return
407		}
408		ok, err := s.canAccessHost(r.Context(), host)
409		if err != nil {
410			s.logger.Error("authz check for rotate-cert", "error", err)
411			writeError(w, http.StatusInternalServerError, "authz check failed")
412			return
413		}
414		if !ok {
415			writeError(w, http.StatusForbidden, "forbidden")
416			return
417		}
418	
419		if newKey {
420			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
421				if errors.Is(err, store.ErrRekeyAlreadyPending) {
422					writeError(w, http.StatusConflict, "rekey already pending")
423					return
424				}
425				s.logger.Error("set pending rekey", "error", err)
426				writeError(w, http.StatusInternalServerError, "failed to schedule rekey")
427				return
428			}
429			s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=true")
430			writeJSON(w, http.StatusAccepted, rotateCertResponse{NewKey: true})
431			return
432		}
433	
434		certInfo, err := s.store.GetCertificateInfo(r.Context(), host.ID)
435		if err != nil {
436			s.logger.Error("get cert info for rotate-cert", "error", err)
437			writeError(w, http.StatusInternalServerError, "no current cert to re-sign")
438			return
439		}
440		signed, err := s.signHostCert(r.Context(), host, certInfo)
441		if err != nil {
442			s.logger.Error("sign cert for rotate-cert", "error", err)
443			writeError(w, http.StatusInternalServerError, "failed to sign new cert")
444			return
445		}
446		if err := s.store.SaveCertificateAndUpdateHostCert(r.Context(), host.ID, signed.certPEM, signed.fp, signed.notBefore, signed.notAfter); err != nil {
447			s.logger.Error("save rotated cert", "error", err)
448			writeError(w, http.StatusInternalServerError, "failed to persist new cert")
449			return
450		}
451		s.metrics.recordSignature(host.CAID)
452		s.recordAuditAction(r.Context(), auditHostRotateCertRequested, host.ID, "new_key=false")
453	
454		writeJSON(w, http.StatusOK, rotateCertResponse{
455			NewKey:         false,
456			CertificatePEM: string(signed.certPEM),
457			CACertPEM:      string(signed.caCertPEM),
458		})
459	}
