461	// handleReenroll is the explicit re-enrollment endpoint (ADR 0004 §7.1).
462	// It delegates to mintEnrollmentTokenForHost — identical mechanics to
463	// handleRegenerateEnrollmentToken — but exists as a separate route so
464	// operator UIs can present "re-enroll" as a discrete action (e.g. when a
465	// host has lost its key material), distinct from the "regenerate token"
466	// fix-up that handleRegenerateEnrollmentToken serves.
467	func (s *Server) handleReenroll(w http.ResponseWriter, r *http.Request) {
468		s.mintEnrollmentTokenForHost(w, r, "reenroll")
469	}
