471	// handleRegenerateEnrollmentToken mints a fresh single-use enrollment token
472	// bound to an existing host row (ADR 0004 §7.1 — "regenerates the token
473	// without churning the row"). Previous active tokens for the same host are
474	// invalidated atomically. The host row, its IP allocation, group membership,
475	// and audit history are preserved.
476	func (s *Server) handleRegenerateEnrollmentToken(w http.ResponseWriter, r *http.Request) {
477		s.mintEnrollmentTokenForHost(w, r, "regenerate-token")
478	}
