525	func (s *Server) handleUpdateHost(w http.ResponseWriter, r *http.Request) {
526		id := chi.URLParam(r, "id")
527	
528		// Load host by ID
529		host, err := s.store.GetHost(r.Context(), id)
530		if errors.Is(err, store.ErrNotFound) {
531			writeError(w, http.StatusNotFound, "host not found")
532			return
533		}
534		if err != nil {
535			s.logger.Error("get host", "error", err)
536			writeError(w, http.StatusInternalServerError, "failed to get host")
537			return
538		}
539		ok, err := s.canAccessHost(r.Context(), host)
540		if err != nil {
541			s.logger.Error("authz check", "error", err)
542			writeError(w, http.StatusInternalServerError, "authz check failed")
543			return
544		}
545		if !ok {
546			writeError(w, http.StatusForbidden, "forbidden")
547			return
548		}
549	
550		// Decode request body (lenient for PATCH, forward-compatible)
551		var req updateHostRequest
552		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
553			writeError(w, http.StatusBadRequest, "invalid request body")
554			return
555		}
556	
557		// Snapshot before state for diff and triggers
558		before := *host
559		if before.Advanced != nil {
560			beforeAdv := *before.Advanced
561			before.Advanced = &beforeAdv
562		}
563	
564		// Validate and merge fields
565		if req.Name != nil {
566			name := strings.TrimSpace(*req.Name)
567			if name == "" {
568				writeError(w, http.StatusBadRequest, "name must not be empty")
569				return
570			}
571			host.Name = name
572		}
573	
574		if req.NebulaIPs != nil {
575			if err := validateHostIPs(r.Context(), s.store, host.NetworkID, *req.NebulaIPs, host.ID); err != nil {
576				if IsHostIPValidationError(err) {
577					writeError(w, http.StatusBadRequest, err.Error())
578					return
579				}
580				s.logger.Error("validate host ips", "error", err)
581				writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
582				return
583			}
584			host.NebulaIPs = *req.NebulaIPs
585		}
586	
587		if req.Groups != nil {
588			for _, g := range *req.Groups {
589				if strings.TrimSpace(g) == "" {
590					writeError(w, http.StatusBadRequest, "group names must not be empty")
591					return
592				}
593			}
594			host.Groups = *req.Groups
595		}
596	
597		if req.Role != nil {
598			role := models.HostRole(*req.Role)
599			if !models.ValidRole(role) {
600				writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", *req.Role))
601				return
602			}
603			host.Role = role
604			host.IsLighthouse = role == models.HostRoleLighthouse
605			host.IsRelay = role == models.HostRoleRelay
606		}
607	
608		if req.PublicIP != nil {
609			publicIP := strings.TrimSpace(*req.PublicIP)
610			if publicIP != "" {
611				if _, err := models.ValidateIPAddr("public_ip", publicIP); err != nil {
612					writeError(w, http.StatusBadRequest, err.Error())
613					return
614				}
615			}
616			host.PublicIP = publicIP
617		}
618	
619		if req.ListenPort != nil {
620			if *req.ListenPort < 0 || *req.ListenPort > 65535 {
621				writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
622				return
623			}
624			host.ListenPort = *req.ListenPort
625		}
626	
627		if req.Advanced != nil {
628			if err := validateHostAdvanced(req.Advanced); err != nil {
629				writeError(w, http.StatusBadRequest, err.Error())
630				return
631			}
632			host.Advanced = req.Advanced
633		}
634	
635		// Validate role reachability
636		if err := models.ValidateRoleReachability(host.Role, host.PublicIP, host.ListenPort); err != nil {
637			writeError(w, http.StatusBadRequest, err.Error())
638			return
639		}
640	
641		// Compute diff
642		diffJSON, hasChanges, err := models.HostDiff(&before, host)
643		if err != nil {
644			s.logger.Error("compute diff", "error", err)
645			writeError(w, http.StatusInternalServerError, "failed to compute diff")
646			return
647		}
648	
649		// If no changes, return 200 without updating
650		if !hasChanges {
651			writeJSON(w, http.StatusOK, host)
652			return
653		}
654	
655		// Update timestamp and persist
656		host.UpdatedAt = time.Now()
657		if err := s.store.UpdateHost(r.Context(), host); err != nil {
658			s.logger.Error("update host", "error", err)
659			writeError(w, http.StatusInternalServerError, "failed to update host")
660			return
661		}
662	
663		// Task 1.4: Re-publish triggers
664		// Force re-publish config for this host
665		if err := s.store.UpdateHostConfigVersion(r.Context(), host.ID, 0); err != nil {
666			s.logger.Error("reset host config version", "host", host.ID, "error", err)
667		}
668	
669		// If role changed, bump network config version for peer updates
670		if before.Role != host.Role {
671			if err := s.store.BumpNetworkConfigVersion(r.Context(), host.NetworkID); err != nil {
672				s.logger.Error("bump network config version", "network", host.NetworkID, "error", err)
673			}
674		}
675	
676		// If name or any IP changed, set pending rekey for cert re-enrollment
677		ipsEqual := len(before.NebulaIPs) == len(host.NebulaIPs)
678		if ipsEqual {
679			for i := range before.NebulaIPs {
680				if before.NebulaIPs[i] != host.NebulaIPs[i] {
681					ipsEqual = false
682					break
683				}
684			}
685		}
686		if before.Name != host.Name || !ipsEqual {
687			if err := s.store.SetPendingRekey(r.Context(), host.ID); err != nil {
688				if !errors.Is(err, store.ErrRekeyAlreadyPending) {
689					s.logger.Error("set pending rekey", "host", host.ID, "error", err)
690				}
691				// Idempotent: ErrRekeyAlreadyPending is success (rekey already scheduled)
692			}
693			// Reload host to get PendingRekey flag in response
694			freshHost, err := s.store.GetHost(r.Context(), host.ID)
695			if err == nil {
696				host = freshHost
697			}
698		}
699	
700		// Record audit entry with diff
701		s.recordAuditAction(r.Context(), auditHostUpdate, host.ID, string(diffJSON))
702	
703		writeJSON(w, http.StatusOK, host)
704	}
