38	// canAccessHost returns true if the actor in ctx is admin, or owns the host's CA.
39	func (s *Server) canAccessHost(ctx context.Context, h *models.Host) (bool, error) {
40		if h == nil {
41			return false, nil
42		}
43		return s.actorOwnsCA(ctx, h.CAID)
44	}
45	
46	// canAccessNetwork returns true if the actor in ctx is admin, or owns the network's CA.
47	func (s *Server) canAccessNetwork(ctx context.Context, n *models.Network) (bool, error) {
48		if n == nil {
49			return false, nil
50		}
51		return s.actorOwnsCA(ctx, n.CAID)
52	}
