44	func (s *Server) handleCreateHost(w http.ResponseWriter, r *http.Request) {
45		var req createHostRequest
46		if err := decodeJSONStrict(r, &req); err != nil {
47			writeError(w, http.StatusBadRequest, err.Error())
48			return
49		}
50	
51		if req.Name == "" || len(req.NebulaIPs) == 0 || req.NetworkID == "" {
52			writeError(w, http.StatusBadRequest, "name, nebula_ips, and network_id are required")
53			return
54		}
55	
56		network, err := s.store.GetNetwork(r.Context(), req.NetworkID)
57		if errors.Is(err, store.ErrNotFound) {
58			writeError(w, http.StatusBadRequest, "network not found")
59			return
60		}
61		if err != nil {
62			s.logger.Error("get network for host create", "error", err)
63			writeError(w, http.StatusInternalServerError, "failed to load network")
64			return
65		}
66		netOK, err := s.canAccessNetwork(r.Context(), network)
67		if err != nil {
68			s.logger.Error("authz check for host create", "error", err)
69			writeError(w, http.StatusInternalServerError, "authz check failed")
70			return
71		}
72		if !netOK {
73			writeError(w, http.StatusForbidden, "forbidden")
74			return
75		}
76	
77		if err := validateHostIPs(r.Context(), s.store, req.NetworkID, req.NebulaIPs, ""); err != nil {
78			if IsHostIPValidationError(err) {
79				writeError(w, http.StatusBadRequest, err.Error())
80				return
81			}
82			s.logger.Error("validate host ips", "error", err)
83			writeError(w, http.StatusInternalServerError, "failed to validate nebula_ips")
84			return
85		}
86		if req.ListenPort < 0 || req.ListenPort > 65535 {
87			writeError(w, http.StatusBadRequest, "listen_port must be between 0 and 65535")
88			return
89		}
90	
91		if strings.TrimSpace(req.PublicIP) != "" {
92			if _, err := models.ValidateIPAddr("public_ip", req.PublicIP); err != nil {
93				writeError(w, http.StatusBadRequest, err.Error())
94				return
95			}
96		}
97	
98		role := models.HostRole(req.Role)
99		if !models.ValidRole(role) {
100			writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid role: %q", req.Role))
101			return
102		}
103		if role == "" {
104			role = models.HostRoleHost
105		}
106		if err := models.ValidateRoleReachability(role, req.PublicIP, req.ListenPort); err != nil {
107			writeError(w, http.StatusBadRequest, err.Error())
108			return
109		}
110	
111		if err := validateHostAdvanced(req.Advanced); err != nil {
112			writeError(w, http.StatusBadRequest, err.Error())
113			return
114		}
115	
116		// Host inherits the network's CA. Combined with the canAccessNetwork
117		// gate above, this binds new hosts to the same trust domain as the
118		// network's operator (closes the GHSA-598g class of cross-tenant cert
119		// issuance via host create + rotate-cert). The defaultCAID fallback
120		// preserves backward compatibility for admin-created networks via the
121		// CAID-less /api/v1/networks endpoint (out-of-scope follow-up).
122		caID := network.CAID
123		if caID == "" {
124			caID = s.defaultCAID
125		}
126		now := time.Now()
127		host := &models.Host{
128			ID:           uuid.New().String(),
129			NetworkID:    req.NetworkID,
130			Name:         req.Name,
131			NebulaIPs:    req.NebulaIPs,
132			Groups:       req.Groups,
133			Role:         role,
134			IsLighthouse: role == models.HostRoleLighthouse,
135			IsRelay:      role == models.HostRoleRelay,
136			PublicIP:     req.PublicIP,
137			ListenPort:   req.ListenPort,
138			Status:       models.HostStatusPending,
139			Advanced:     req.Advanced,
140			CAID:         caID,
141			CreatedAt:    now,
142			UpdatedAt:    now,
143		}
144		if host.Groups == nil {
145			host.Groups = []string{}
146		}
147		for _, g := range host.Groups {
148			if strings.TrimSpace(g) == "" {
149				writeError(w, http.StatusBadRequest, "group names must not be empty")
150				return
151			}
152		}
153	
154		rawToken := uuid.New().String()
155		token := &models.EnrollmentToken{
156			ID:        uuid.New().String(),
157			HostID:    host.ID,
158			TokenHash: models.HashEnrollmentToken(rawToken),
159			ExpiresAt: now.Add(s.tokenTTLFor(r.Context(), host.NetworkID)),
160			CreatedAt: now,
161		}
162		if err := s.store.CreateHostAndToken(r.Context(), host, token); err != nil {
163			s.logger.Error("create host and token", "error", err)
164			writeError(w, http.StatusInternalServerError, "failed to create host")
165			return
166		}
167		s.recordAuditAction(r.Context(), auditHostCreate, host.ID, host.Name)
168	
169		writeJSON(w, http.StatusCreated, createHostResponse{
170			Host:            host,
171			EnrollmentToken: rawToken,
172		})
173	}
