480	// mintEnrollmentTokenForHost is the shared implementation of the
481	// regenerate-token and reenroll endpoints. The reason argument flows into
482	// the audit details column so the timeline distinguishes the two.
483	func (s *Server) mintEnrollmentTokenForHost(w http.ResponseWriter, r *http.Request, reason string) {
484		id := chi.URLParam(r, "id")
485		host, err := s.store.GetHost(r.Context(), id)
486		if errors.Is(err, store.ErrNotFound) {
487			writeError(w, http.StatusNotFound, "host not found")
488			return
489		}
490		if err != nil {
491			s.logger.Error("get host", "error", err)
492			writeError(w, http.StatusInternalServerError, "failed to get host")
493			return
494		}
495		ok, err := s.canAccessHost(r.Context(), host)
496		if err != nil {
497			s.logger.Error("authz check", "error", err)
498			writeError(w, http.StatusInternalServerError, "authz check failed")
499			return
500		}
501		if !ok {
502			writeError(w, http.StatusForbidden, "forbidden")
503			return
504		}
505	
506		tokenStr := uuid.New().String()
507		expiresAt := time.Now().Add(s.tokenTTLFor(r.Context(), host.NetworkID))
508		if err := s.store.CreateTokenForHost(r.Context(), host.ID, tokenStr, expiresAt); err != nil {
509			s.logger.Error("create enrollment token", "error", err)
510			writeError(w, http.StatusInternalServerError, "failed to mint token")
511			return
512		}
513		details := host.Name
514		if reason != "" {
515			details = reason + ": " + host.Name
516		}
517		s.recordAuditAction(r.Context(), auditHostReenrollRequested, host.ID, details)
518	
519		writeJSON(w, http.StatusCreated, regenerateEnrollmentTokenResponse{
520			Token:     tokenStr,
521			ExpiresAt: expiresAt,
522		})
523	}
