192	func (s *Server) handleRotateCA(w http.ResponseWriter, r *http.Request) {
193		id := chi.URLParam(r, "id")
194		oldCA, err := s.store.GetCA(r.Context(), id)
195		if errors.Is(err, store.ErrNotFound) {
196			writeError(w, http.StatusNotFound, "CA not found")
197			return
198		}
199		if err != nil {
200			s.logger.Error("get ca", "error", err)
201			writeError(w, http.StatusInternalServerError, "failed to get CA")
202			return
203		}
204		if !s.canAccessCA(r, oldCA) {
205			writeError(w, http.StatusForbidden, "you do not own this CA")
206			return
207		}
208	
209		newCA, err := pki.RotateAndStoreCA(r.Context(), s.store, s.master, s.logger, oldCA)
210		if err != nil {
211			if errors.Is(err, pki.ErrMasterRequired) {
212				writeError(w, http.StatusBadRequest, "master key not configured")
213				return
214			}
215			s.logger.Error("rotate ca", "error", err)
216			writeError(w, http.StatusInternalServerError, "failed to rotate CA")
217			return
218		}
219	
220		s.recordAuditAction(r.Context(), auditCARotated, newCA.ID, fmt.Sprintf("predecessor=%s", oldCA.ID))
221		writeJSON(w, http.StatusOK, s.toCAResponse(newCA))
222	}
