64	func (s *Server) handleUpdateFirewall(w http.ResponseWriter, r *http.Request) {
65		networkID := chi.URLParam(r, "id")
66	
67		network, err := s.store.GetNetwork(r.Context(), networkID)
68		if errors.Is(err, store.ErrNotFound) {
69			writeError(w, http.StatusNotFound, "network not found")
70			return
71		}
72		if err != nil {
73			s.logger.Error("get network for firewall update", "error", err)
74			writeError(w, http.StatusInternalServerError, "failed to load network")
75			return
76		}
77		ok, err := s.canAccessNetwork(r.Context(), network)
78		if err != nil {
79			s.logger.Error("authz check", "error", err)
80			writeError(w, http.StatusInternalServerError, "authz check failed")
81			return
82		}
83		if !ok {
84			writeError(w, http.StatusForbidden, "forbidden")
85			return
86		}
87	
88		var req firewallRulesRequest
89		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
90			writeError(w, http.StatusBadRequest, "invalid request body")
91			return
92		}
93	
94		for _, rules := range [][]firewallRule{req.Inbound, req.Outbound} {
95			for _, rule := range rules {
96				if rule.Port == "" {
97					writeError(w, http.StatusBadRequest, "firewall rule port must not be empty")
98					return
99				}
100				if rule.Proto == "" {
101					writeError(w, http.StatusBadRequest, "firewall rule proto must not be empty")
102					return
103				}
104			}
105		}
106	
107		rulesJSON, err := json.Marshal(req)
108		if err != nil {
109			writeError(w, http.StatusInternalServerError, "failed to marshal rules")
110			return
111		}
112		if err := s.store.SetNetworkConfigAndBumpVersion(r.Context(), networkID, "firewall", string(rulesJSON)); err != nil {
113			s.logger.Error("set firewall rules", "error", err)
114			writeError(w, http.StatusInternalServerError, "failed to update firewall rules")
115			return
116		}
117	
118		s.logger.Info("firewall rules updated", "network", networkID)
119		writeJSON(w, http.StatusOK, req)
120	}
