122	func (s *Server) getFirewallRules(r *http.Request, networkID string) (*firewallRulesRequest, error) {
123		val, err := s.store.GetNetworkConfig(r.Context(), networkID, "firewall")
124		if errors.Is(err, store.ErrNotFound) {
125			rules := defaultFirewallRules
126			return &rules, nil
127		}
128		if err != nil {
129			return nil, err
130		}
131	
132		var rules firewallRulesRequest
133		if err := json.Unmarshal([]byte(val), &rules); err != nil {
134			return nil, fmt.Errorf("unmarshal firewall rules: %w", err)
135		}
136		return &rules, nil
137	}
