130	func (s *SQLiteStore) ListCAsApproachingExpiry(ctx context.Context, thresholdRatio float64) ([]*models.CA, error) {
131		// Query for active CAs where remaining lifetime <= threshold * total lifetime.
132		// SQLite stores times as RFC3339 strings, so we extract just the date portion (YYYY-MM-DD)
133		// and use julianday() for date arithmetic.
134		// Calculation: (not_after_days - now_days) / (not_after_days - not_before_days) <= threshold
135		rows, err := s.db.QueryContext(ctx, `
136			SELECT `+caColumns+` FROM cas
137			WHERE status = ?
138			  AND (julianday(SUBSTR(not_after, 1, 10)) - julianday(SUBSTR(datetime('now'), 1, 10))) /
139			       (julianday(SUBSTR(not_after, 1, 10)) - julianday(SUBSTR(not_before, 1, 10))) <= ?
140			ORDER BY not_after ASC
141		`, models.CAStatusActive, thresholdRatio)
142		if err != nil {
143			return nil, fmt.Errorf("list CAs approaching expiry: %w", err)
144		}
145		defer func() {
146			if err := rows.Close(); err != nil {
147				slog.Error("close rows", "error", err)
148			}
149		}()
150		out := make([]*models.CA, 0)
151		for rows.Next() {
152			c, err := scanCA(rows)
153			if err != nil {
154				return nil, fmt.Errorf("scan CA: %w", err)
155			}
156			out = append(out, c)
157		}
158		return out, rows.Err()
159	}
