188	// DeleteCA removes a CA row. The DB-level ON DELETE RESTRICT on
189	// networks.ca_id (when enforced by application logic) is mirrored here:
190	// the call returns an error if networks still reference the CA, so the
191	// operator must retire / move networks first.
192	func (s *SQLiteStore) DeleteCA(ctx context.Context, id string) error {
193		row := s.db.QueryRowContext(ctx, `SELECT COUNT(1) FROM networks WHERE ca_id = ?`, id)
194		var n int
195		if err := row.Scan(&n); err != nil {
196			return fmt.Errorf("check CA references: %w", err)
197		}
198		if n > 0 {
199			return fmt.Errorf("CA still has %d network(s); detach them first", n)
200		}
201		result, err := s.db.ExecContext(ctx, `DELETE FROM cas WHERE id = ?`, id)
202		if err != nil {
203			return fmt.Errorf("delete CA: %w", err)
204		}
205		rows, err := result.RowsAffected()
206		if err != nil {
207			return fmt.Errorf("delete CA rows: %w", err)
208		}
209		if rows == 0 {
210			return ErrNotFound
211		}
212		return nil
213	}
