215	// CountEmptyCAIDRows counts the total number of rows across networks, hosts,
216	// certificates, and blocklist tables that have an empty ca_id. This is used
217	// at startup to detect rows from the pre-multi-CA era that have not been
218	// backfilled with a CA owner.
219	func (s *SQLiteStore) CountEmptyCAIDRows(ctx context.Context) (int, error) {
220		const q = `
221			SELECT
222			  (SELECT COUNT(*) FROM networks WHERE ca_id IS NULL OR ca_id = '') +
223			  (SELECT COUNT(*) FROM hosts WHERE ca_id IS NULL OR ca_id = '') +
224			  (SELECT COUNT(*) FROM certificates WHERE ca_id IS NULL OR ca_id = '') +
225			  (SELECT COUNT(*) FROM blocklist WHERE ca_id IS NULL OR ca_id = '')
226		`
227		var n int
228		err := s.db.QueryRowContext(ctx, q).Scan(&n)
229		if err != nil {
230			return 0, fmt.Errorf("count empty ca_id rows: %w", err)
231		}
232		return n, nil
233	}
