72	// requestLogger returns middleware that logs requests.
73	func requestLogger(logger *slog.Logger) func(http.Handler) http.Handler {
74		return func(next http.Handler) http.Handler {
75			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
76				start := time.Now()
77				ww := &responseWriter{ResponseWriter: w, status: http.StatusOK}
78				next.ServeHTTP(ww, r)
79				logger.Info("request",
80					"method", r.Method,
81					"path", r.URL.Path,
82					"status", ww.status,
83					"duration", time.Since(start),
84				)
85			})
86		}
87	}
