11	// actorOwnsCA returns true if the actor in ctx is admin, or owns the CA with caID.
12	// Returns (false, nil) for empty caID or ErrNotFound. Errors only for unexpected DB errors.
13	func (s *Server) actorOwnsCA(ctx context.Context, caID string) (bool, error) {
14		if actorIsAdmin(ctx) {
15			return true, nil
16		}
17		if caID == "" {
18			return false, nil
19		}
20		actor := ActorOf(ctx)
21		if actor == nil {
22			// actorIsAdmin returned false but ActorOf is nil — defensive; treat as
23			// forbidden. Unreachable on the current bearerAuth path; if it ever
24			// fires it usually means middleware ordering regressed, so log loud.
25			s.logger.Warn("authz: nil actor with non-admin context — bearerAuth ordering regression?", "ca_id", caID)
26			return false, nil
27		}
28		ca, err := s.store.GetCA(ctx, caID)
29		if err != nil {
30			if errors.Is(err, store.ErrNotFound) {
31				return false, nil
32			}
33			return false, err
34		}
35		return ca.OwnerOperatorID == actor.ID, nil
36	}
