157	func (s *Server) handleDeleteCA(w http.ResponseWriter, r *http.Request) {
158		id := chi.URLParam(r, "id")
159		c, err := s.store.GetCA(r.Context(), id)
160		if errors.Is(err, store.ErrNotFound) {
161			writeError(w, http.StatusNotFound, "CA not found")
162			return
163		}
164		if err != nil {
165			writeError(w, http.StatusInternalServerError, "failed to load CA")
166			return
167		}
168		if !s.canAccessCA(r, c) {
169			writeError(w, http.StatusForbidden, "you do not own this CA")
170			return
171		}
172		if c.ID == s.defaultCAID {
173			writeError(w, http.StatusForbidden, "the default CA cannot be deleted")
174			return
175		}
176		if err := s.store.DeleteCA(r.Context(), id); err != nil {
177			writeError(w, http.StatusConflict, err.Error())
178			return
179		}
180		s.recordAuditAction(r.Context(), auditCADeleted, id, "")
181		w.WriteHeader(http.StatusNoContent)
182	}
