31	func (s *Server) handleEnroll(w http.ResponseWriter, r *http.Request) {
32		var req enrollRequest
33		if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
34			writeError(w, http.StatusBadRequest, "invalid request body")
35			return
36		}
37	
38		if req.Token == "" || req.PublicKeyPEM == "" {
39			writeError(w, http.StatusBadRequest, "token and public_key_pem are required")
40			return
41		}
42		if _, err := decodeSigningPublicKeyPEM(req.SigningPubPEM); err != nil {
43			s.metrics.recordEnrollment(resultDenied)
44			writeError(w, http.StatusBadRequest, "signing_public_key_pem is required and must be Ed25519")
45			return
46		}
47	
48		// Consume token (validates one-time use and expiry)
49		tok, err := s.store.ConsumeToken(r.Context(), req.Token)
50		if errors.Is(err, store.ErrNotFound) {
51			s.metrics.recordEnrollment(resultDenied)
52			writeError(w, http.StatusUnauthorized, "invalid enrollment token")
53			return
54		}
55		if errors.Is(err, store.ErrTokenUsed) {
56			s.metrics.recordEnrollment(resultDenied)
57			writeError(w, http.StatusConflict, "enrollment token already used")
58			return
59		}
60		if errors.Is(err, store.ErrTokenExpired) {
61			s.metrics.recordEnrollment(resultDenied)
62			writeError(w, http.StatusGone, "enrollment token expired")
63			return
64		}
65		if err != nil {
66			s.metrics.recordEnrollment(resultError)
67			s.logger.Error("consume token", "error", err)
68			writeError(w, http.StatusInternalServerError, "enrollment failed")
69			return
70		}
71	
72		// Get host
73		host, err := s.store.GetHost(r.Context(), tok.HostID)
74		if errors.Is(err, store.ErrNotFound) {
75			s.metrics.recordEnrollment(resultError)
76			writeError(w, http.StatusInternalServerError, "host not found")
77			return
78		}
79		if err != nil {
80			s.metrics.recordEnrollment(resultError)
81			s.logger.Error("get host for enrollment", "error", err)
82			writeError(w, http.StatusInternalServerError, "enrollment failed")
83			return
84		}
85	
86		// Get network
87		network, err := s.store.GetNetwork(r.Context(), host.NetworkID)
88		if errors.Is(err, store.ErrNotFound) {
89			s.metrics.recordEnrollment(resultError)
90			writeError(w, http.StatusInternalServerError, "network not found")
91			return
92		}
93		if err != nil {
94			s.metrics.recordEnrollment(resultError)
95			s.logger.Error("get network for enrollment", "error", err)
96			writeError(w, http.StatusInternalServerError, "enrollment failed")
97			return
98		}
99	
100		// Parse public key from PEM
101		pubKey, _, _, err := cert.UnmarshalPublicKeyFromPEM([]byte(req.PublicKeyPEM))
102		if err != nil {
103			s.metrics.recordEnrollment(resultDenied)
104			writeError(w, http.StatusBadRequest, "invalid public key PEM")
105			return
106		}
107	
108		prefixes, err := buildHostPrefixes(network, host.NebulaIPs)
109		if err != nil {
110			s.metrics.recordEnrollment(resultError)
111			s.logger.Error("build host prefixes", "error", err, "host_id", host.ID)
112			writeError(w, http.StatusInternalServerError, "enrollment failed")
113			return
114		}
115	
116		// Resolve the CA that owns this host's network and sign with it.
117		caMgr, err := s.caForHost(r.Context(), host)
118		if err != nil {
119			s.metrics.recordEnrollment(resultError)
120			s.logger.Error("resolve host CA", "error", err, "host", host.ID, "ca_id", host.CAID)
121			writeError(w, http.StatusInternalServerError, "enrollment failed")
122			return
123		}
124		defer caMgr.Wipe() // GHSA-8h84-fhqq-q58v: zeroise plaintext CA key on return.
125		hostCert, caCertPEM, err := func() (cert.Certificate, []byte, error) {
126			c, signErr := caMgr.Sign(pki.SignRequest{
127				Name:      host.Name,
128				PublicKey: pubKey,
129				Networks:  prefixes,
130				Groups:    host.Groups,
131				Duration:  pki.DefaultAgentCertDuration,
132			})
133			if signErr != nil {
134				return nil, nil, signErr
135			}
136			ca, caErr := caMgr.CACertPEM()
137			if caErr != nil {
138				return nil, nil, caErr
139			}
140			return c, ca, nil
141		}()
142		if err != nil {
143			s.metrics.recordEnrollment(resultError)
144			s.logger.Error("sign certificate", "error", err)
145			writeError(w, http.StatusInternalServerError, "enrollment failed")
146			return
147		}
148		s.metrics.recordSignature(host.CAID)
149	
150		// Post-sign work — no CA lock needed
151		certPEM, err := hostCert.MarshalPEM()
152		if err != nil {
153			s.metrics.recordEnrollment(resultError)
154			s.logger.Error("marshal cert PEM", "error", err)
155			writeError(w, http.StatusInternalServerError, "enrollment failed")
156			return
157		}
158	
159		fp, err := hostCert.Fingerprint()
160		if err != nil {
161			s.metrics.recordEnrollment(resultError)
162			s.logger.Error("cert fingerprint", "error", err)
163			writeError(w, http.StatusInternalServerError, "enrollment failed")
164			return
165		}
166	
167		// Save certificate and enroll host atomically
168		if err := s.store.SaveCertificateAndEnrollHost(r.Context(), host.ID, certPEM, fp, hostCert.NotBefore(), hostCert.NotAfter()); err != nil {
169			s.metrics.recordEnrollment(resultError)
170			s.logger.Error("save certificate and enroll host", "error", err)
171			writeError(w, http.StatusInternalServerError, "enrollment failed")
172			return
173		}
174	
175		// Bind the Ed25519 signing public key to the host so subsequent poll
176		// signatures verify against it (ADR 0004 §7.1).
177		if err := s.store.UpdateHostSigningPub(r.Context(), host.ID, req.SigningPubPEM); err != nil {
178			s.metrics.recordEnrollment(resultError)
179			s.logger.Error("update host signing pub", "error", err)
180			writeError(w, http.StatusInternalServerError, "enrollment failed")
181			return
182		}
183	
184		// Pin the freshly-enrolled host to the current network config version so the
185		// next agent poll does not redundantly re-send the same config we already
186		// embedded in the enrollment response below.
187		networkVersion, err := s.store.GetNetworkConfigVersion(r.Context(), host.NetworkID)
188		if err != nil {
189			s.metrics.recordEnrollment(resultError)
190			s.logger.Error("get network config version", "error", err)
191			writeError(w, http.StatusInternalServerError, "enrollment failed")
192			return
193		}
194		if err := s.store.UpdateHostConfigVersion(r.Context(), host.ID, networkVersion); err != nil {
195			s.metrics.recordEnrollment(resultError)
196			s.logger.Error("update host config version", "error", err)
197			writeError(w, http.StatusInternalServerError, "enrollment failed")
198			return
199		}
200	
201		configYAML, err := s.renderHostConfig(r.Context(), host)
202		if err != nil {
203			s.metrics.recordEnrollment(resultError)
204			s.logger.Error("generate config", "error", err)
205			writeError(w, http.StatusInternalServerError, "enrollment failed")
206			return
207		}
208	
209		s.metrics.recordEnrollment(resultOK)
210		writeJSON(w, http.StatusOK, enrollResponse{
211			CertificatePEM:   string(certPEM),
212			CACertificatePEM: string(caCertPEM),
213			ConfigYAML:       string(configYAML),
214		})
215	}
