294	// getLighthouses returns every enrolled lighthouse in the given network. Pending
295	// or blocked lighthouses are excluded so peer configs never advertise hosts that
296	// cannot yet (or no longer) accept traffic.
297	func (s *Server) getLighthouses(ctx context.Context, networkID string) ([]configgen.LighthouseInfo, error) {
298		hosts, err := s.store.ListHosts(ctx, store.HostFilter{
299			NetworkID: networkID,
300			Status:    models.HostStatusEnrolled,
301		})
302		if err != nil {
303			return nil, err
304		}
305	
306		result := make([]configgen.LighthouseInfo, 0)
307		for _, h := range hosts {
308			if !h.IsLighthouse || h.PublicIP == "" {
309				continue
310			}
311			if len(h.NebulaIPs) == 0 {
312				continue
313			}
314			port := h.ListenPort
315			if port == 0 {
316				port = 4242
317			}
318			result = append(result, configgen.LighthouseInfo{
319				NebulaIPs:  h.NebulaIPs,
320				PublicAddr: fmt.Sprintf("%s:%d", h.PublicIP, port),
321			})
322		}
323		return result, nil
324	}
